content.title:
Run $targets = @(
  'papers_sources/Are aligned neural networks adversarially aligned 2306.15447',
  'papers_sources/Hyena Hierarchy 2302.10866',
  'papers_sources/Maintaining Plasticity in Deep Continual Learning',
  'papers_sources/MeanSparse 2406.05927',
  'papers_sources/2302.10866.tar',
  'papers_sources/2306.15447.tar',
  'papers_sources/2402.01220-source.tar'
);
foreach ($t in $targets) {
  $item = Get-Item -LiteralPath $t
  if ($item.PSIsContainer) {
    $size = (Get-ChildItem -LiteralPath $t -Recurse -File | Measure-Object -Property Length -Sum).Sum
  } else {
    $size = $item.Length
  }
  "{0}`t{1}`t{2:o}`t{3}" -f $t, ($(if($item.PSIsContainer){'dir'}else{'file'})), $item.LastWriteTime, $size
}

