content.title:
Run $notes = Get-ChildItem -LiteralPath 'notes' -File -Filter '*.md' | Where-Object { $_.Name -notin @('index.md','Research-Paper-Notes 导入索引.md') };
foreach ($n in $notes) {
  $lines = Get-Content -LiteralPath $n.FullName -Encoding utf8;
  $idx = ($lines | Select-String -Pattern '^## 14\. 一句话总结').LineNumber;
  $sum = '';
  if ($idx) {
    for ($i=$idx; $i -lt [Math]::Min($idx+6, $lines.Count); $i++) {
      if ($lines[$i] -match '^\-\s') { $sum = $lines[$i] -replace '^\-\s*',''; break }
    }
  }
  if (-not $sum) { $sum = '(未提取到 14 节一句话总结)'; }
  "### $($n.BaseName)`n$sum`n"
}

