content.title:
Run $notes = Get-ChildItem -LiteralPath 'notes' -File -Filter '*.md' | Where-Object { $_.Name -notin @('index.md','Research-Paper-Notes 导入索引.md') } | Sort-Object Name;
$rows = @();
foreach ($n in $notes) {
  $noteRaw = Get-Content -LiteralPath $n.FullName -Raw -Encoding utf8;
  $refPath = Join-Path (Get-Location) ("references/" + $n.BaseName + ".md");
  $refExists = Test-Path -LiteralPath $refPath;
  if (-not $refExists -and $n.BaseName -eq 'MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature') {
    $refPath = Join-Path (Get-Location) 'references/MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature Sparsification.md';
    $refExists = Test-Path -LiteralPath $refPath;
  }
  $refRaw = '';
  if ($refExists) { $refRaw = Get-Content -LiteralPath $refPath -Raw -Encoding utf8 }

  $row = [PSCustomObject]@{
    note = $n.BaseName
    ref_exists = $refExists
    note_ref_links = ([regex]::Matches($noteRaw,'\[\[references\/')).Count
    note_concept_links = ([regex]::Matches($noteRaw,'\[\[concepts\/')).Count
    note_entity_links = ([regex]::Matches($noteRaw,'\[\[entities\/')).Count
    note_synthesis_links = ([regex]::Matches($noteRaw,'\[\[synthesis\/')).Count
    ref_concept_links = (if($refExists){([regex]::Matches($refRaw,'\[\[concepts\/')).Count}else{0})
    ref_entity_links = (if($refExists){([regex]::Matches($refRaw,'\[\[entities\/')).Count}else{0})
    ref_synthesis_links = (if($refExists){([regex]::Matches($refRaw,'\[\[synthesis\/')).Count}else{0})
  }
  $rows += $row
}
$rows | ConvertTo-Json -Depth 3

