content.title:
Run $pages = Get-ChildItem -Recurse -File -Filter '*.md' | Where-Object { $_.FullName -notmatch '\\.obsidian\\|\\_archives\\' };
function Count-Incoming($target){
  $pattern = "\[\[[^\]]*$([regex]::Escape($target))(\||\]\])";
  $count = 0;
  foreach($p in $pages){
    if($p.Name -eq 'index.md'){ continue }
    $raw = Get-Content -LiteralPath $p.FullName -Raw -Encoding utf8;
    if($raw -match $pattern){ $count++ }
  }
  return $count
}
"-- concepts incoming<=2 --";
Get-ChildItem -LiteralPath 'concepts' -File -Filter '*.md' | Where-Object { $_.Name -ne 'index.md' } | ForEach-Object {
  $c = Count-Incoming $_.BaseName
  [PSCustomObject]@{name=$_.BaseName; incoming=$c}
} | Where-Object { $_.incoming -le 2 } | Sort-Object incoming,name | ForEach-Object { "{0}`t{1}" -f $_.name,$_.incoming };
"-- entities incoming<=2 --";
Get-ChildItem -LiteralPath 'entities' -File -Filter '*.md' | Where-Object { $_.Name -ne 'index.md' } | ForEach-Object {
  $c = Count-Incoming $_.BaseName
  [PSCustomObject]@{name=$_.BaseName; incoming=$c}
} | Where-Object { $_.incoming -le 2 } | Sort-Object incoming,name | ForEach-Object { "{0}`t{1}" -f $_.name,$_.incoming };
"-- synthesis incoming<=2 --";
Get-ChildItem -LiteralPath 'synthesis' -File -Filter '*.md' | Where-Object { $_.Name -ne 'index.md' } | ForEach-Object {
  $c = Count-Incoming $_.BaseName
  [PSCustomObject]@{name=$_.BaseName; incoming=$c}
} | Where-Object { $_.incoming -le 2 } | Sort-Object incoming,name | ForEach-Object { "{0}`t{1}" -f $_.name,$_.incoming }

