content.title:
Run $notes = Get-ChildItem -LiteralPath 'notes' -File -Filter '*.md' | Where-Object { $_.Name -notin @('index.md','Research-Paper-Notes 导入索引.md') };
$updated = 0;
foreach ($n in $notes) {
  $path = $n.FullName
  $raw = Get-Content -LiteralPath $path -Raw -Encoding utf8
  if ($raw -match "(?m)^##\s*Wiki\s*关联") { continue }

  $refRel = "references/$($n.BaseName).md"
  if (-not (Test-Path -LiteralPath $refRel) -and $n.BaseName -eq 'MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature') {
    $refRel = 'references/MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature Sparsification.md'
  }
  if (-not (Test-Path -LiteralPath $refRel)) { continue }

  $refRaw = Get-Content -LiteralPath $refRel -Raw -Encoding utf8
  $concept = ([regex]::Matches($refRaw,'\[\[concepts\/[^\]]+\]\]') | Select-Object -First 1).Value
  $entity = ([regex]::Matches($refRaw,'\[\[entities\/[^\]]+\]\]') | Select-Object -First 1).Value
  $synthesis = ([regex]::Matches($refRaw,'\[\[synthesis\/[^\]]+\]\]') | Select-Object -First 1).Value

  if (-not $concept) { $concept = '待补充' }
  if (-not $entity) { $entity = '待补充' }
  if (-not $synthesis) { $synthesis = '待补充' }

  $refLink = "[[references/$($n.BaseName)|$($n.BaseName)]]"
  if ($n.BaseName -eq 'MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature') {
    $refLink = '[[references/MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature Sparsification|MeanSparse Post-Training Robustness Enhancement Through Mean-Centered Feature Sparsification]]'
  }

  $append = "`r`n`r`n## Wiki 关联`r`n`r`n- 参考摘要：$refLink`r`n- 概念锚点：$concept`r`n- 实体锚点：$entity`r`n- 综合页面：$synthesis`r`n"
  [System.IO.File]::WriteAllText($path, $raw + $append, [System.Text.Encoding]::UTF8)
  $updated++
}
"notes_updated=$updated"

