  $rows += [PSCustomObject]@{
    ref_exists=$refExists
    ref_c=([regex]::Matches($refRaw,'\[\[concepts\/')).Count
    ref_e=([regex]::Matches($refRaw,'\[\[entities\/')).Count
    ref_s=([regex]::Matches($refRaw,'\[\[synthesis\/')).Count
    note_r=([regex]::Matches($noteRaw,'\[\[references\/')).Count
    note_c=([regex]::Matches($noteRaw,'\[\[concepts\/')).Count
    note_e=([regex]::Matches($noteRaw,'\[\[entities\/')).Count
    note_s=([regex]::Matches($noteRaw,'\[\[synthesis\/')).Count
  }
}
"missing_refs=" + (($rows | Where-Object { -not $_.ref_exists }).Count);
"ref_no_concept=" + (($rows | Where-Object { $_.ref_c -eq 0 }).Count);
"ref_no_entity=" + (($rows | Where-Object { $_.ref_e -eq 0 }).Count);
"ref_no_synthesis=" + (($rows | Where-Object { $_.ref_s -eq 0 }).Count);
"note_no_ref=" + (($rows | Where-Object { $_.note_r -eq 0 }).Count);
"note_no_concept=" + (($rows | Where-Object { $_.note_c -eq 0 }).Count);
"note_no_entity=" + (($rows | Where-Object { $_.note_e -eq 0 }).Count);
"note_no_synthesis=" + (($rows | Where-Object { $_.note_s -eq 0 }).Count);

