Run $pages = Get-ChildItem -Recurse -File -Filter '*.md' | Where-Object { $_.FullName -notmatch '\\.obsidian\\|\\_archives\\' };
$orphans = @();
foreach ($p in $pages) {
  if ($p.DirectoryName -notmatch '\\(references|concepts|entities|synthesis)$') { continue }
  if ($p.Name -eq 'index.md') { continue }
  $target = $p.BaseName
  $pattern = "\[\[[^\]]*$([regex]::Escape($target))(\||\]\])"
  $incoming = 0
  foreach ($q in $pages) {
    if ($q.FullName -eq $p.FullName) { continue }
    $text = Get-Content -LiteralPath $q.FullName -Raw -Encoding utf8
    if ($text -match $pattern) { $incoming++ }
  }
  if ($incoming -eq 0) { $orphans += $p.FullName }
}
"orphans_count=$($orphans.Count)"

