content.title:
Run @'
$refs = Get-ChildItem -File 'references' -Filter '*.md' | Where-Object { $_.Name -ne 'index.md' }
$result = foreach($f in $refs){
  $c = Get-Content -Raw -Encoding UTF8 $f.FullName
  $concept = ([regex]::Matches($c, '\[\[concepts/[^\]|]+')).Count
  $entity = ([regex]::Matches($c, '\[\[entities/[^\]|]+')).Count
  $syn = ([regex]::Matches($c, '\[\[synthesis/[^\]|]+')).Count
  [pscustomobject]@{Reference=$f.BaseName; Concepts=$concept; Entities=$entity; Synthesis=$syn; Total=$concept+$entity+$syn}
}
$result | Sort-Object Total, Concepts, Entities, Synthesis | ConvertTo-Json -Depth 3
'@ | powershell -NoProfile -

