content.title:
Run $files = @(
  'papers_sources/Are aligned neural networks adversarially aligned 2306.15447/main.tex',
  'papers_sources/Delving into Decision-based Black-box Attacks on Semantic Segmentation/main.tex',
  'papers_sources/Hyena Hierarchy 2302.10866/1_introduction.tex',
  'papers_sources/Hyena Hierarchy 2302.10866/2_preliminaries.tex',
  'papers_sources/Hyena Hierarchy 2302.10866/3_hyena.tex',
  'papers_sources/Maintaining Plasticity in Deep Continual Learning/arxiv.tex',
  'papers_sources/MeanSparse 2406.05927/main.tex',
  'papers_sources/Research-Paper-Notes/CIF.md',
  'papers_sources/Research-Paper-Notes/GPT-ST预训练时空框架.md',
  'papers_sources/Research-Paper-Notes/Hyena.md',
  'papers_sources/Research-Paper-Notes/LLM体现出时空概念.md',
  'papers_sources/Research-Paper-Notes/PanGu-π.md'
)
foreach($f in $files){
  if(Test-Path $f){
    Write-Output "===== $f ====="
    $content = Get-Content -Raw -Encoding UTF8 $f
    $title = [regex]::Matches($content,'\\title\{([^}]*)\}') | ForEach-Object { $_.Groups[1].Value }
    $author = [regex]::Matches($content,'\\author\{([\s\S]*?)\}') | ForEach-Object { ($_.Groups[1].Value -replace '\\and','; ' -replace '\\',' ' -replace '\s+',' ').Trim() }
    if($title.Count -gt 0){ Write-Output ('TITLE: ' + ($title -join ' | ')) }
    if($author.Count -gt 0){ Write-Output ('AUTHOR: ' + ($author -join ' | ')) }
    $sections = [regex]::Matches($content,'\\(?:sub)*section\*?\{([^}]*)\}') | ForEach-Object { $_.Groups[1].Value.Trim() }
    if($sections.Count -gt 0){ Write-Output ('SECTIONS: ' + (($sections | Select-Object -First 12) -join ' || ')) }
    if($f -like '*.md'){
      $heads = [regex]::Matches($content,'(?m)^#+\s+(.+)$') | ForEach-Object { $_.Groups[1].Value.Trim() }
      if($heads.Count -gt 0){ Write-Output ('HEADINGS: ' + (($heads | Select-Object -First 16) -join ' || ')) }
    }
  }
}

